import{_ as o,C as i,o as a,c as r,a2 as s,b as c,w as n,a as d,E as l,a3 as p}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"Summary and Exercises","description":"Review the core Rust and CLI concepts from Chapter 1 and solidify your understanding with hands-on exercises.","frontmatter":{"title":"Summary and Exercises","description":"Review the core Rust and CLI concepts from Chapter 1 and solidify your understanding with hands-on exercises."},"headers":[],"relativePath":"learn/project/01-hello-rust-cli/12-summary-and-exercises.md","filePath":"learn/project/01-hello-rust-cli/12-summary-and-exercises.md"}'),u={name:"learn/project/01-hello-rust-cli/12-summary-and-exercises.md"};function h(m,e,g,y,b,f){const t=i("Mermaid");return a(),r("div",null,[e[1]||(e[1]=s(`<h1 id="summary-and-exercises" tabindex="-1">Summary and Exercises <a class="header-anchor" href="#summary-and-exercises" aria-label="Permalink to &quot;Summary and Exercises&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How all the Chapter 1 concepts connect to form the foundation of your coding agent</li><li>How to extend the REPL with new commands and features as a self-directed exercise</li><li>How to diagnose common beginner mistakes using the Rust compiler&#39;s error messages</li></ul></blockquote><p>You have come a long way in this chapter. You started with zero Rust knowledge and now have a working interactive REPL — a real program you can compile, run, and interact with. Let&#39;s review what you learned, connect the pieces, and then challenge you with exercises that reinforce each concept.</p><h2 id="what-you-built" tabindex="-1">What You Built <a class="header-anchor" href="#what-you-built" aria-label="Permalink to &quot;What You Built&quot;">​</a></h2><p>Here is a bird&#39;s-eye view of the coding agent skeleton you built in this chapter:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>kodai/</span></span>
<span class="line"><span>  Cargo.toml              # Project manifest with clap and rustyline</span></span>
<span class="line"><span>  Cargo.lock              # Pinned dependency versions</span></span>
<span class="line"><span>  src/</span></span>
<span class="line"><span>    main.rs               # CLI parsing, REPL loop, and command handlers</span></span></code></pre></div><p>The code snapshot keeps everything in a single <code>main.rs</code> for clarity -- you can see the entire program at a glance. In a production codebase, you would split this into modules (<code>lib.rs</code>, <code>commands.rs</code>, etc.), but for learning, one file makes it easier to follow the flow from CLI parsing through command dispatch to user interaction.</p><p>This program:</p><ol><li><strong>Parses CLI arguments</strong> with <code>clap</code> — supports <code>--verbose</code>, <code>--model</code>, and an optional prompt</li><li><strong>Starts an interactive REPL</strong> using <code>rustyline</code> for line editing and history</li><li><strong>Dispatches commands</strong> — <code>/help</code>, <code>/quit</code>, <code>/clear</code>, and user messages</li><li><strong>Handles errors gracefully</strong> — EOF, Ctrl+C, invalid commands all produce clean responses</li><li><strong>Persists history</strong> — previous commands survive across sessions</li></ol><h2 id="concept-map" tabindex="-1">Concept Map <a class="header-anchor" href="#concept-map" aria-label="Permalink to &quot;Concept Map&quot;">​</a></h2><p>Here is how every concept from this chapter connects:</p>`,11)),(a(),c(p,null,{default:n(()=>[l(t,{id:"mermaid-74",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20CARGO%5B%22Cargo.toml%5Cndependencies%22%5D%0A%20%20%20%20RUN%5B%22cargo%20run%5Cnbuild%20%2B%20execute%22%5D%0A%20%20%20%20CRATES%5B%22clap%2C%20rustyline%5Cncrate%20ecosystem%22%5D%0A%20%20%20%20MAIN%5B%22src%2Fmain.rs%5Cnentry%20point%22%5D%0A%20%20%20%20CLI%5B%22CLI%20Parsing%5Cnclap%20derive%22%5D%0A%20%20%20%20REPL%5B%22REPL%20Loop%5Cnloop%20%2B%20match%22%5D%0A%20%20%20%20MODS%5B%22Modules%5Cnmod%2C%20pub%2C%20use%22%5D%0A%20%20%20%20STRUCTS%5B%22Struct%20types%5CnVariables%20and%20Types%22%5D%0A%20%20%20%20DISPATCH%5B%22Command%20Dispatch%5CnFunctions%20%2B%20Enums%22%5D%0A%20%20%20%20ERRORS%5B%22Error%20Handling%5CnResult%2C%20Option%2C%20%3F%22%5D%0A%20%20%20%20INPUT%5B%22User%20Input%5Cnstdin%2C%20rustyline%22%5D%0A%0A%20%20%20%20CARGO%20--%3E%20RUN%0A%20%20%20%20CARGO%20--%3E%20CRATES%0A%20%20%20%20RUN%20--%3E%20MAIN%0A%20%20%20%20CRATES%20--%3E%20MAIN%0A%20%20%20%20MAIN%20--%3E%20CLI%0A%20%20%20%20MAIN%20--%3E%20REPL%0A%20%20%20%20MAIN%20--%3E%20MODS%0A%20%20%20%20CLI%20--%3E%20STRUCTS%0A%20%20%20%20REPL%20--%3E%20DISPATCH%0A%20%20%20%20STRUCTS%20--%3E%20DISPATCH%0A%20%20%20%20DISPATCH%20--%3E%20ERRORS%0A%20%20%20%20ERRORS%20--%3E%20INPUT%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=s(`<p>Every topic builds on the ones before it. CLI parsing requires understanding structs and types. The REPL loop uses functions, pattern matching, and error handling. Modules organize everything into a maintainable structure.</p><h2 id="key-rust-concepts-summary" tabindex="-1">Key Rust Concepts Summary <a class="header-anchor" href="#key-rust-concepts-summary" aria-label="Permalink to &quot;Key Rust Concepts Summary&quot;">​</a></h2><h3 id="from-python-to-rust-quick-reference" tabindex="-1">From Python to Rust: Quick Reference <a class="header-anchor" href="#from-python-to-rust-quick-reference" aria-label="Permalink to &quot;From Python to Rust: Quick Reference&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Python</th><th>Rust</th><th>Notes</th></tr></thead><tbody><tr><td><code>def func():</code></td><td><code>fn func()</code></td><td><code>fn</code> keyword, curly braces for body</td></tr><tr><td><code>x = 5</code></td><td><code>let x = 5;</code></td><td>Immutable by default</td></tr><tr><td><code>x = 5</code> (mutable)</td><td><code>let mut x = 5;</code></td><td>Explicit mutability</td></tr><tr><td><code>str</code></td><td><code>String</code> / <code>&amp;str</code></td><td>Owned vs. borrowed</td></tr><tr><td><code>list</code></td><td><code>Vec&lt;T&gt;</code></td><td>Type parameter required</td></tr><tr><td><code>dict</code></td><td><code>HashMap&lt;K, V&gt;</code></td><td>Type parameters required</td></tr><tr><td><code>None</code></td><td><code>Option::None</code></td><td>Part of the <code>Option&lt;T&gt;</code> enum</td></tr><tr><td><code>try/except</code></td><td><code>Result&lt;T, E&gt;</code> + <code>?</code></td><td>Compile-time error checking</td></tr><tr><td><code>import module</code></td><td><code>mod module;</code> + <code>use</code></td><td>Explicit declaration required</td></tr><tr><td><code>pip install</code></td><td><code>cargo add</code></td><td>Single tool for everything</td></tr><tr><td><code>python script.py</code></td><td><code>cargo run</code></td><td>Compile then execute</td></tr><tr><td><code>pytest</code></td><td><code>cargo test</code></td><td>Built into the toolchain</td></tr><tr><td><code>black .</code></td><td><code>cargo fmt</code></td><td>Built into the toolchain</td></tr><tr><td><code>pylint</code></td><td><code>cargo clippy</code></td><td>Built into the toolchain</td></tr></tbody></table><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>The biggest mindset shift is not any single syntax difference — it is that Rust&#39;s compiler is your collaborator. In Python, you run code to find bugs. In Rust, you talk to the compiler. When <code>cargo check</code> shows errors, read them carefully — they almost always tell you exactly what to fix. Over time, you will start thinking of the compiler as a pair programmer that catches your mistakes before they reach production.</p></div><h2 id="common-beginner-mistakes" tabindex="-1">Common Beginner Mistakes <a class="header-anchor" href="#common-beginner-mistakes" aria-label="Permalink to &quot;Common Beginner Mistakes&quot;">​</a></h2><p>Here are the errors you are most likely to encounter in your first week of Rust, with explanations and fixes.</p><h3 id="_1-forgetting-mut" tabindex="-1">1. Forgetting <code>mut</code> <a class="header-anchor" href="#_1-forgetting-mut" aria-label="Permalink to &quot;1. Forgetting \`mut\`&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>error[E0384]: cannot assign twice to immutable variable \`x\`</span></span>
<span class="line"><span> --&gt; src/main.rs:3:5</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>2 |     let x = 5;</span></span>
<span class="line"><span>  |         - first assignment</span></span>
<span class="line"><span>3 |     x = 10;</span></span>
<span class="line"><span>  |     ^^^^^^ cannot assign twice to immutable variable</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>help: consider making this binding mutable</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>2 |     let mut x = 5;</span></span>
<span class="line"><span>  |         +++</span></span></code></pre></div><p><strong>Fix:</strong> Add <code>mut</code> if you need to change the variable. If you do not, that is the compiler telling you the variable should not be changed.</p><h3 id="_2-using-a-moved-value" tabindex="-1">2. Using a moved value <a class="header-anchor" href="#_2-using-a-moved-value" aria-label="Permalink to &quot;2. Using a moved value&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>error[E0382]: borrow of moved value: \`s1\`</span></span>
<span class="line"><span> --&gt; src/main.rs:4:20</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>2 |     let s1 = String::from(&quot;hello&quot;);</span></span>
<span class="line"><span>  |         -- move occurs because \`s1\` has type \`String\`</span></span>
<span class="line"><span>3 |     let s2 = s1;</span></span>
<span class="line"><span>  |              -- value moved here</span></span>
<span class="line"><span>4 |     println!(&quot;{s1}&quot;);</span></span>
<span class="line"><span>  |               ^^ value borrowed here after move</span></span></code></pre></div><p><strong>Fix:</strong> Use <code>.clone()</code> to create a copy, or use a reference (<code>&amp;s1</code>) instead of moving ownership.</p><h3 id="_3-missing-semicolon-or-extra-semicolon" tabindex="-1">3. Missing semicolon (or extra semicolon) <a class="header-anchor" href="#_3-missing-semicolon-or-extra-semicolon" aria-label="Permalink to &quot;3. Missing semicolon (or extra semicolon)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>error[E0308]: mismatched types</span></span>
<span class="line"><span> --&gt; src/main.rs:2:5</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>1 | fn add(a: i32, b: i32) -&gt; i32 {</span></span>
<span class="line"><span>  |                            --- expected \`i32\` because of return type</span></span>
<span class="line"><span>2 |     a + b;</span></span>
<span class="line"><span>  |          ^ expected \`i32\`, found \`()\`</span></span></code></pre></div><p><strong>Fix:</strong> Remove the semicolon from the last expression to return it. <code>a + b;</code> is a statement (returns nothing). <code>a + b</code> is an expression (returns the sum).</p><h3 id="_4-type-mismatch-with-str-and-string" tabindex="-1">4. Type mismatch with &amp;str and String <a class="header-anchor" href="#_4-type-mismatch-with-str-and-string" aria-label="Permalink to &quot;4. Type mismatch with &amp;str and String&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>error[E0308]: mismatched types</span></span>
<span class="line"><span> --&gt; src/main.rs:5:16</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>5 |     takes_string(name);</span></span>
<span class="line"><span>  |                  ^^^^</span></span>
<span class="line"><span>  |                  expected \`String\`, found \`&amp;str\`</span></span></code></pre></div><p><strong>Fix:</strong> Use <code>.to_string()</code> or <code>String::from()</code> to convert <code>&amp;str</code> to <code>String</code>. Use <code>&amp;</code> to borrow a <code>String</code> as <code>&amp;str</code>.</p><h3 id="_5-unused-result-warning" tabindex="-1">5. Unused Result warning <a class="header-anchor" href="#_5-unused-result-warning" aria-label="Permalink to &quot;5. Unused Result warning&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>warning: unused \`Result\` that must be used</span></span>
<span class="line"><span> --&gt; src/main.rs:3:5</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>3 |     fs::write(&quot;output.txt&quot;, &quot;hello&quot;);</span></span>
<span class="line"><span>  |     ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  = note: this \`Result\` may be an \`Err\` variant, which should be handled</span></span></code></pre></div><p><strong>Fix:</strong> Handle the <code>Result</code> with <code>?</code>, <code>.expect()</code>, or <code>match</code>. Do not silently ignore it.</p><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><p>Practice each concept with these exercises. They are ordered by difficulty and build on the REPL you created.</p><h3 id="exercise-1-add-a-history-command-easy" tabindex="-1">Exercise 1: Add a /history Command (Easy) <a class="header-anchor" href="#exercise-1-add-a-history-command-easy" aria-label="Permalink to &quot;Exercise 1: Add a /history Command (Easy)&quot;">​</a></h3><p>Add a <code>/history</code> built-in command that prints the last 10 commands the user entered. You need to store commands in a <code>Vec&lt;String&gt;</code> and pass it to the command handler.</p><p><strong>Hints:</strong></p><ul><li>Declare <code>let mut history: Vec&lt;String&gt; = Vec::new();</code> before the REPL loop</li><li>Push each command into <code>history</code> before processing it</li><li>In the handler, use <code>.iter().rev().take(10)</code> to get the last 10 entries</li></ul><h3 id="exercise-2-add-a-echo-command-with-arguments-easy" tabindex="-1">Exercise 2: Add a /echo Command with Arguments (Easy) <a class="header-anchor" href="#exercise-2-add-a-echo-command-with-arguments-easy" aria-label="Permalink to &quot;Exercise 2: Add a /echo Command with Arguments (Easy)&quot;">​</a></h3><p>Add a <code>/echo</code> command that echoes back everything after <code>/echo</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>kodai&gt; /echo Hello, world!</span></span>
<span class="line"><span>Hello, world!</span></span></code></pre></div><p><strong>Hints:</strong></p><ul><li>In <code>handle_builtin</code>, match on <code>cmd</code> that starts with <code>&quot;echo &quot;</code> using <code>cmd.strip_prefix(&quot;echo &quot;)</code></li><li>Return the remaining text as the response</li></ul><h3 id="exercise-3-add-a-count-command-medium" tabindex="-1">Exercise 3: Add a /count Command (Medium) <a class="header-anchor" href="#exercise-3-add-a-count-command-medium" aria-label="Permalink to &quot;Exercise 3: Add a /count Command (Medium)&quot;">​</a></h3><p>Add a <code>/count</code> command that shows how many messages the user has sent (not counting built-in commands). Track this with a <code>u32</code> counter.</p><p><strong>Hints:</strong></p><ul><li>Declare <code>let mut message_count: u32 = 0;</code> before the loop</li><li>Increment it only when <code>handle_command</code> processes a user message (not a <code>/</code>-prefixed command)</li><li>You may need to change your function signatures or use a return value to signal whether the input was a user message</li></ul><h3 id="exercise-4-multi-line-input-medium" tabindex="-1">Exercise 4: Multi-Line Input (Medium) <a class="header-anchor" href="#exercise-4-multi-line-input-medium" aria-label="Permalink to &quot;Exercise 4: Multi-Line Input (Medium)&quot;">​</a></h3><p>Add support for multi-line input. When a line ends with <code>\\</code>, continue reading the next line and concatenate them:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>kodai&gt; This is a long \\</span></span>
<span class="line"><span>...&gt;   multi-line message</span></span>
<span class="line"><span>You said: This is a long multi-line message</span></span></code></pre></div><p><strong>Hints:</strong></p><ul><li>After reading a line, check if it ends with <code>\\</code> using <code>.ends_with(&#39;\\\\&#39;)</code></li><li>If it does, change the prompt to <code>&quot;...&gt; &quot;</code> and keep reading</li><li>Accumulate lines in a <code>String</code> using <code>.push_str()</code></li><li>Trim the trailing <code>\\</code> from each continuation line</li></ul><h3 id="exercise-5-command-aliases-with-a-hashmap-hard" tabindex="-1">Exercise 5: Command Aliases with a HashMap (Hard) <a class="header-anchor" href="#exercise-5-command-aliases-with-a-hashmap-hard" aria-label="Permalink to &quot;Exercise 5: Command Aliases with a HashMap (Hard)&quot;">​</a></h3><p>Implement a <code>/alias</code> command that lets users create shortcuts:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>kodai&gt; /alias h /help</span></span>
<span class="line"><span>Alias created: h -&gt; /help</span></span>
<span class="line"><span>kodai&gt; h</span></span>
<span class="line"><span>Available commands: ...</span></span></code></pre></div><p><strong>Hints:</strong></p><ul><li>Store aliases in a <code>HashMap&lt;String, String&gt;</code></li><li>Before processing input, check if it matches an alias key</li><li>If it does, replace the input with the alias value and process that instead</li><li>Handle edge cases: aliasing to another alias, aliasing a built-in command name</li></ul><h3 id="exercise-6-input-validation-and-error-types-hard" tabindex="-1">Exercise 6: Input Validation and Error Types (Hard) <a class="header-anchor" href="#exercise-6-input-validation-and-error-types-hard" aria-label="Permalink to &quot;Exercise 6: Input Validation and Error Types (Hard)&quot;">​</a></h3><p>Create a custom <code>InputError</code> enum with variants for different invalid input scenarios (empty input, input too long, invalid UTF-8). Use <code>Result&lt;CommandResult, InputError&gt;</code> as the return type for your command handler instead of returning <code>CommandResult</code> directly.</p><p><strong>Hints:</strong></p><ul><li>Define <code>enum InputError { Empty, TooLong(usize), InvalidCommand(String) }</code></li><li>Implement <code>Display</code> for <code>InputError</code></li><li>Change <code>handle_command</code> to return <code>Result&lt;CommandResult, InputError&gt;</code></li><li>Handle the <code>Result</code> in the REPL loop with a <code>match</code></li></ul><h2 id="what-comes-next" tabindex="-1">What Comes Next <a class="header-anchor" href="#what-comes-next" aria-label="Permalink to &quot;What Comes Next&quot;">​</a></h2><p>In Chapter 2, you replace the echo response in <code>handle_user_message()</code> with a real LLM API call. You learn how to:</p><ul><li>Make HTTP requests with the <code>reqwest</code> crate</li><li>Serialize and deserialize JSON with <code>serde</code></li><li>Handle API errors and rate limits</li><li>Stream responses token by token to the terminal</li></ul><p>The REPL you built here is the foundation. Every new feature plugs into this structure — the loop stays the same, the command handlers grow, and the agent becomes more capable with each chapter.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>You built a complete, working CLI application in Rust: a REPL with argument parsing, command dispatch, error handling, line editing, and persistent history.</li><li>The Rust compiler is your best debugging tool. Read its error messages carefully — they point directly to the problem and usually suggest the fix.</li><li>The key Rust concepts you learned — immutability, ownership, <code>Result</code>/<code>Option</code>, modules, and enums — are the building blocks for everything that follows.</li><li>Your REPL&#39;s architecture (loop + command dispatch + separated handlers) is the same architecture used by production coding agents. You are building on a real foundation.</li><li>Practice the exercises to internalize these concepts. Each one isolates a specific skill (collections, string processing, error handling, HashMap) that you need in upcoming chapters.</li></ul>`,57))])}const w=o(u,[["render",h]]);export{C as __pageData,w as default};
